(function() {
    'use strict';

    // ללא jQuery — DOMContentLoaded native למנוע race condition
    function ready(fn) {
        if (document.readyState !== 'loading') fn();
        else document.addEventListener('DOMContentLoaded', fn);
    }

    ready(function() {
        var params = nouvello_chat_engine_params;
        if (!params || !params.cn) return; // לא מחובר

        // שמור על אותו פורמט URL בדיוק כמו המקור
        // server_url נשלח גם כ-param — כך עבד המקור, לא משנים
        var queryStr = new URLSearchParams(params).toString();
        queryStr += '&timezone=' + Intl.DateTimeFormat().resolvedOptions().timeZone;
        queryStr += '&dir=' + (document.body.classList.contains('rtl') ? 'rtl' : 'ltr');
        queryStr += '&height=' + window.innerHeight;

        var iframeSrc = params.server_url + '/chat/wp-widget?' + queryStr;

        var iframe = document.createElement('iframe');
        iframe.setAttribute('src', iframeSrc);
        iframe.setAttribute('id', 'nouvello-chat-engine');
        iframe.style.position = 'fixed';
        iframe.style.zIndex = '99999';
        iframe.style.right = '0px';
        iframe.style.bottom = '0px';
        iframe.style.border = '0';
        iframe.style.width = '100%';
        iframe.style.height = '100%';
        iframe.style.maxWidth = '0px';
        iframe.style.maxHeight = '0px';
        document.body.appendChild(iframe);

        // postMessage ל-iframe — שמור על '*' בדיוק כמו המקור
        var iframeEl = document.getElementById('nouvello-chat-engine');
        var sendMessage = function(msg) {
            iframeEl.contentWindow.postMessage(msg, '*');
        };

        // listener — זהה למקור
        window.addEventListener('message', function(e) {
            if (typeof e.data === 'string' || e.data instanceof String) {
                parseMessage(iframe, e.data);
            }
        }, false);
    });

    function parseMessage(iframe, data) {
        try {
            var jsonData = JSON.parse(data);
            if (!jsonData || !jsonData.target || jsonData.target !== 'nouvello_chat_widget' || !jsonData.action) return;
            switch (jsonData.action) {
                case 'widget_position':
                    if (jsonData.top) iframe.style.top = jsonData.top;
                    if (jsonData.bottom) iframe.style.bottom = jsonData.bottom;
                    if (jsonData.left) iframe.style.left = jsonData.left;
                    if (jsonData.right) iframe.style.right = jsonData.right;
                    break;
                case 'show_widget':
                    iframe.style.maxWidth = '55px';
                    iframe.style.maxHeight = '55px';
                    break;
                case 'hide_widget':
                    iframe.style.maxWidth = '0px';
                    iframe.style.maxHeight = '0px';
                    break;
                case 'open_widget':
                    iframe.style.maxWidth = '400px';
                    iframe.style.maxHeight = '600px';
                    setTimeout(function() {
                        iframe.style.boxShadow = '0px 1px 9px -3px rgb(0 0 0 / 10%)';
                    }, 380);
                    break;
                case 'close_widget':
                    iframe.style.boxShadow = 'none';
                    setTimeout(function() {
                        iframe.style.maxWidth = '55px';
                        iframe.style.maxHeight = '55px';
                    }, 300);
                    break;
            }
        } catch (err) {}
    }

})();